SELECT ROUND(bed_utilization_rate, 2) AS rounded_bed_utilization_rate
FROM bed_utilization_logs
WHERE log_id = 0;

SELECT total_open_staffed_beds 
FROM bed_utilization_logs 
WHERE unit = 'HSC_MICU';

SELECT unit, AVG(bed_utilization_rate) AS average_utilization
FROM bed_utilization_logs
GROUP BY unit;

SELECT log_time, unit, total_open_staffed_beds, bed_utilization_rate
FROM bed_utilization_logs
ORDER BY log_time DESC;

SELECT units.unit_name
FROM bed_utilization_logs
INNER JOIN units ON bed_utilization_logs.unit = units.unit_id
WHERE bed_utilization_logs.bed_utilization_rate = (
  SELECT MAX(bed_utilization_rate) FROM bed_utilization_logs
);
